\operatorname{OrIENT3D}(\mathbf{a}, \mathbf{b}, \mathbf{c}, \mathbf{d}) & =\overrightarrow{\mathbf{a d}} \cdot(\overrightarrow{\mathbf{b d}} \times \overrightarrow{\mathbf{c d}}) \\
& =\operatorname{det}(\overrightarrow{\mathbf{a d}}, \overrightarrow{\mathbf{b d}}, \overrightarrow{\mathbf{c d}}) \\
& =\left|\begin{array}{lll}
a_{x}-d_{x} & a_{y}-d_{y} & a_{z}-d_{z} \\
