c_{x}-d_{x} & c_{y}-d_{y} & c_{z}-d_{z}
\end{array}\right| \\
& =\left|\begin{array}{llll}
a_{x} & a_{y} & a_{z} & 1 \\
b_{x} & b_{y} & b_{z} & 1 \\
c_{x} & c_{y} & c_{z} & 1 \\
d_{x} & d_{y} & d_{z} & 1
\end{array}\right|
\end{aligned}
